mapper.select:
SELECT AS dd, SUM(uus.TOTAL) AS total, SUM(uus.HIT_CNT1) AS hitCnt1, SUM(uus.HIT_CNT2) AS hitCnt2, SUM(uus.HIT_CNT3) AS hitCnt3, SUM(uus.HIT_CNT4) AS hitCnt4, SUM(uus.ARIN_USE_CNT) AS arinUseCnt, uus.TOTAL_OUTPUT_CNT AS totalOutCnt, TRUNCATE((SUM(uus.HIT_CNT1) * 100.0) / NULLIF(SUM(uus.TOTAL), 0), 2) AS hitCnt1Per, TRUNCATE((SUM(uus.HIT_CNT2) * 100.0) / NULLIF(SUM(uus.TOTAL), 0), 2) AS hitCnt2Per, TRUNCATE((SUM(uus.HIT_CNT3) * 100.0) / NULLIF(SUM(uus.TOTAL), 0), 2) AS hitCnt3Per, TRUNCATE((SUM(uus.HIT_CNT4) * 100.0) / NULLIF(SUM(uus.TOTAL), 0), 2) AS hitCnt4Per, TRUNCATE((SUM(uus.ARIN_USE_CNT) * 100.0) / NULLIF(SUM(uus.TOTAL), 0), 2) AS arinUsePer FROM USER_USAGE_STAT uus WHERE 1 = 1
AND uus.TYPE = #{searchLearningType}
AND uus.HDQR_BOB_DCD = #{searchTarget}
AND uus.RSRE_YMD BETWEEN #{searchStartDate} AND #{searchEndDate}
GROUP BY dd

SELECT AS dd, SUM(aps.TOTAL) AS total, SUM(aps.HIT_CNT1) AS hitCnt1, SUM(aps.HIT_CNT2) AS hitCnt2, SUM(aps.HIT_CNT3) AS hitCnt3, SUM(aps.HIT_CNT4) AS hitCnt4, SUM(aps.ARIN_USE_CNT) AS arinUseCnt, TRUNCATE((SUM(aps.HIT_CNT1) * 100.0) / NULLIF(SUM(aps.TOTAL), 0), 2) AS hitCnt1Per, TRUNCATE((SUM(aps.HIT_CNT2) * 100.0) / NULLIF(SUM(aps.TOTAL), 0), 2) AS hitCnt2Per, TRUNCATE((SUM(aps.HIT_CNT3) * 100.0) / NULLIF(SUM(aps.TOTAL), 0), 2) AS hitCnt3Per, TRUNCATE((SUM(aps.HIT_CNT4) * 100.0) / NULLIF(SUM(aps.TOTAL), 0), 2) AS hitCnt4Per, TRUNCATE((SUM(aps.ARIN_USE_CNT) * 100.0) / NULLIF(SUM(aps.TOTAL), 0), 2) AS arinUsePer FROM AI_PRFR_STAT aps WHERE 1 = 1
AND aps.TYPE = #{searchLearningType}
AND aps.HDQR_BOB_DCD = #{searchTarget}
AND aps.BDGT_PRFR_YMD BETWEEN #{searchStartDate} AND #{searchEndDate}
GROUP BY dd

